content:
{
  "sentences": [
    {
      "text": "這家餐廳的價格跟那家差不多。",
      "pinyin": "Zhè jiā cāntīng de jiàgé gēn nà jiā chàbùduō.",
      "pinyin_numeric": "zhe4 jia1 can1ting1 de5 jia4ge2 gen1 na4 jia1 cha4bu4duo1",
      "translation_en": "The price at this restaurant is about the same as that one.",
      "translation_ko": "이 식당의 가격은 저 식당과 비슷합니다."
    },
    {
      "text": "牛肉麵的味道跟滷肉飯差不多。",
      "pinyin": "Niúròu miàn de wèidào gēn lǔròu fàn chàbùduō.",
      "pinyin_numeric": "niu2rou4 mian4 de5 wei4dao4 gen1 lu3rou4 fan4 cha4bu4duo1",
      "translation_en": "The flavor of beef noodles is similar to that of braised pork rice.",
      "translation_ko": "소고기 국수의 맛은 루로우판과 비슷합니다."
    },
    {
      "text": "便利商店的價錢跟超市差不多。",
      "pinyin": "Biànlì shāngdiàn de jiàqián gēn chāoshì chàbùduō.",
      "pinyin_numeric": "bian4li4 shang1dian4 de5 jia4qian2 gen1 chao1shi4 cha4bu4duo1",
      "translation_en": "The prices at convenience stores are about the same as at supermarkets.",
      "translation_ko": "편의점의 가격은 슈퍼마켓과 비슷합니다."
    },
    {
      "text": "這杯拿鐵的口感跟那杯差不多。",
      "pinyin": "Zhè bēi nǎtiě de kǒugǎn gēn nà bēi chàbùduō.",
      "pinyin_numeric": "zhe4 bei1 na3tie3 de5 kou3gan3 gen1 na4 bei1 cha4bu4duo1",
      "translation_en": "The texture of this latte is similar to that one.",
      "translation_ko": "이 라떼의 식감은 저 라떼와 비슷합니다."
    },
    {
      "text": "捷運的方便程度跟公車差不多。",
      "pinyin": "Jiéyùn de fāngbiàn chéngdù gēn gōngchē chàbùduō.",
      "pinyin_numeric": "jie2yun4 de5 fang1bian4 cheng2du4 gen1 gong1che1 cha4bu4duo1",
      "translation_en": "The convenience of the MRT is about the same as the bus.",
      "translation_ko": "지하철의 편리함은 버스와 비슷합니다."
    },
    {
      "text": "這家小吃店的環境跟夜市差不多。",
      "pinyin": "Zhè jiā xiǎochī diàn de huánjìng gēn yèshì chàbùduō.",
      "pinyin_numeric": "zhe4 jia1 xiao3chi1 dian4 de5 huan2jing4 gen1 ye4shi4 cha4bu4duo1",
      "translation_en": "The atmosphere at this snack shop is similar to that of the night market.",
      "translation_ko": "이 간이 식당의 분위기는 야시장과 비슷합니다."
    },
    {
      "text": "這份炒飯的份量跟那份差不多。",
      "pinyin": "Zhè fèn chǎofàn de fènliàng gēn nà fèn chàbùduō.",
      "pinyin_numeric": "zhe4 fen4 chao3fan4 de5 fen4liang4 gen1 na4 fen4 cha4bu4duo1",
      "translation_en": "The portion size of this fried rice is about the same as that one.",
      "translation_ko": "이 볶음밥의 양은 저 볶음밥과 비슷합니다."
    },
    {
      "text": "這家店的服務態度跟那家差不多。",
      "pinyin": "Zhè jiā diàn de fúwù tàidù gēn nà jiā chàbùduō.",
      "pinyin_numeric": "zhe4 jia1 dian4 de5 fu2wu4 tai4du4 gen1 na4 jia1 cha4bu4duo1",
      "translation_en": "The service attitude at this store is about the same as that one.",
      "translation_ko": "이 가게의 서비스 태도는 저 가게와 비슷합니다."
    },
    {
      "text": "從這裡到車站的距離跟到學校差不多。",
      "pinyin": "Cóng zhèlǐ dào chēzhàn de jùlí gēn dào xuéxiào chàbùduō.",
      "pinyin_numeric": "cong2 zhe4li3 dao4 che1zhan4 de5 ju4li2 gen1 dao4 xue2xiao4 cha4bu4duo1",
      "translation_en": "The distance from here to the station is about the same as to the school.",
      "translation_ko": "여기에서 역까지의 거리는 학교까지와 비슷합니다."
    },
    {
      "text": "這家店的品質跟那家差不多，可是價格比較便宜。",
      "pinyin": "Zhè jiā diàn de pǐnzhí gēn nà jiā chàbùduō, kěshì jiàgé bǐjiào piányí.",
      "pinyin_numeric": "zhe4 jia1 dian4 de5 pin3zhi2 gen1 na4 jia1 cha4bu4duo1, ke3shi4 jia4ge2 bi3jiao4 pian2yi2",
      "translation_en": "The quality at this store is about the same as that one, but the price is cheaper.",
      "translation_ko": "이 가게의 품질은 저 가게와 비슷하지만 가격이 더 저렴합니다."
    }
  ]
}
